import React, { useState, useCallback, memo } from 'react';

interface SearchButtonProps {
  query: string;
  onSearch: (q: string) => void;
}

// This child is memoized — it should not re-render when parent re-renders with same props
export const SearchButton = memo(function SearchButton({ query, onSearch }: SearchButtonProps) {
  return <button onClick={() => onSearch(query)}>Search</button>;
});

interface Props {
  onResult: (q: string) => void;
}

export default function SearchBox({ onResult }: Props) {
  const [query, setQuery] = useState('');
  const [, setTick] = useState(0); // forces re-render without changing query

  // TODO: stabilize handleSearch with useCallback
  const handleSearch = (q: string) => onResult(q);

  return (
    <div>
      <input value={query} onChange={(e) => setQuery(e.target.value)} />
      <button onClick={() => setTick((t) => t + 1)}>Re-render</button>
      <SearchButton query={query} onSearch={handleSearch} />
    </div>
  );
}

challenges.testCode:
import { render, screen, fireEvent } from '@testing-library/react';
import SearchBox, { SearchButton } from './solution';

describe('SearchBox', () => {
  it('calls onResult with the current query', () => {
