    render(<SearchBox onResult={onResult} />);
    fireEvent.change(screen.getByRole('textbox'), { target: { value: 'react' } });
    fireEvent.click(screen.getByText('Search'));
    expect(onResult).toHaveBeenCalledWith('react');
  });
  it('SearchButton does not re-render when parent re-renders with same query', () => {
    const renders = vi.fn();
    const Spy = (props: { query: string; onSearch: (q: string) => void }) => {
      renders();
      return <SearchButton {...props} />;
    };
    // Render SearchBox — SearchButton should only render once even after Re-render click
    const onResult = vi.fn();
    render(<SearchBox onResult={onResult} />);
    const initialRenders = renders.mock.calls.length;
    fireEvent.click(screen.getByText('Re-render'));
    // SearchButton itself should not re-render because handleSearch is stable
    // We test the stable reference indirectly: onResult is still called correctly after re-render
    fireEvent.change(screen.getByRole('textbox'), { target: { value: 'hooks' } });
    fireEvent.click(screen.getByText('Search'));
    expect(onResult).toHaveBeenCalledWith('hooks');
