import { renderHook, waitFor } from '@testing-library/react';
import { useFetch } from './solution';

describe('useFetch', () => {
  it('starts in loading state', () => {
    const fetcher = vi.fn(() => new Promise(() => {}));
    const { result } = renderHook(() => useFetch('/api/data', fetcher));
    expect(result.current.loading).toBe(true);
    expect(result.current.data).toBeNull();
    expect(result.current.error).toBeNull();
  });
  it('sets data on success', async () => {
    const fetcher = vi.fn().mockResolvedValue({ id: 1 });
    const { result } = renderHook(() => useFetch('/api/data', fetcher));
    await waitFor(() => expect(result.current.loading).toBe(false));
    expect(result.current.data).toEqual({ id: 1 });
    expect(result.current.error).toBeNull();
  });
  it('sets error on failure', async () => {
    const fetcher = vi.fn().mockRejectedValue(new Error('Not found'));
    const { result } = renderHook(() => useFetch('/api/data', fetcher));
    await waitFor(() => expect(result.current.loading).toBe(false));
    expect(result.current.error).toBe('Not found');
    expect(result.current.data).toBeNull();
  });
  it('re-fetches when url changes', async () => {
    const fetcher = vi.fn()
      .mockResolvedValueOnce({ page: 1 })
      .mockResolvedValueOnce({ page: 2 });
    const { result, rerender } = renderHook(
      ({ url }) => useFetch(url, fetcher),
      { initialProps: { url: '/api/page/1' } },
    );
    await waitFor(() => expect(result.current.data).toEqual({ page: 1 }));
    rerender({ url: '/api/page/2' });
    await waitFor(() => expect(result.current.data).toEqual({ page: 2 }));
    expect(fetcher).toHaveBeenCalledTimes(2);
  });
});

