import { Container } from './solution';

describe('Container', () => {
  it('resolves a registered primitive factory', () => {
    const c = new Container();
    c.register('greeting', () => 'hello');
    expect(c.resolve('greeting')).toBe('hello');
  });
  it('throws for unregistered token', () => {
    const c = new Container();
    expect(() => c.resolve('missing')).toThrow('Token not registered: missing');
  });
  it('resolves class instances', () => {
    class Logger { tag = 'log'; }
    const c = new Container();
    c.register('logger', () => new Logger());
    expect(c.resolve<Logger>('logger')).toBeInstanceOf(Logger);
  });
  it('calls the factory each time (transient)', () => {
    let count = 0;
    const c = new Container();
    c.register('counter', () => ++count);
    c.resolve('counter');
    c.resolve('counter');
    expect(count).toBe(2);
  });
  it('wires nested dependencies', () => {
    class Database { name = 'db'; }
    class Repository { constructor(public db: Database) {} }
    const c = new Container();
    c.register('db', () => new Database());
    c.register('repo', () => new Repository(c.resolve<Database>('db')));
    const repo = c.resolve<Repository>('repo');
    expect(repo.db.name).toBe('db');
  });
});
